import{_ as i,o as e,c as o,ag as t}from"./chunks/framework.Cqf6AMW8.js";const h=JSON.parse('{"title":"C语言数据存储","description":"C语言数据存储相关知识，包括基本数据类型、多数据存储类型和关键字。","frontmatter":{"title":"C语言数据存储","description":"C语言数据存储相关知识，包括基本数据类型、多数据存储类型和关键字。","date":"2026-04-21T00:00:00.000Z","tags":["C语言","数据存储"],"sidebar":"auto"},"headers":[],"relativePath":"docs/backend/C/c-1-数据存储.md","filePath":"docs/backend/C/c-1-数据存储.md","lastUpdated":1776715536000}'),a={name:"docs/backend/C/c-1-数据存储.md"};function c(r,l,d,n,s,u){return e(),o("div",null,[...l[0]||(l[0]=[t('<h1 id="后端" tabindex="-1">后端 <a class="header-anchor" href="#后端" aria-label="Permalink to &quot;后端&quot;">​</a></h1><p>======================================================</p><h2 id="c语言数据存储" tabindex="-1">C语言数据存储 <a class="header-anchor" href="#c语言数据存储" aria-label="Permalink to &quot;C语言数据存储&quot;">​</a></h2><h2 id="_1-基本数据类型" tabindex="-1">1. 基本数据类型 <a class="header-anchor" href="#_1-基本数据类型" aria-label="Permalink to &quot;1. 基本数据类型&quot;">​</a></h2><ul><li><p><strong>char</strong>：字符型</p><ul><li>大小：1字节</li><li>取值范围：-128 到 127</li><li>示例：<code>char c = &#39;A&#39;;</code></li></ul></li><li><p><strong>int</strong>：整型</p><ul><li>大小：4字节</li><li>取值范围：-2147483648 到 2147483647</li><li>示例：<code>int i = 100000;</code></li></ul></li><li><p><strong>float</strong>：单精度浮点型</p><ul><li>大小：4字节</li><li>取值范围：±3.4e-38 到 ±3.4e+38</li><li>示例：<code>float f = 3.14f;</code></li></ul></li><li><p><strong>double</strong>：双精度浮点型</p><ul><li>大小：8字节</li><li>取值范围：±1.7e-308 到 ±1.7e+308</li><li>示例：<code>double d = 3.1415926535;</code></li></ul></li><li><p><strong>void</strong>：空类型</p><ul><li>大小：0字节</li><li>说明：表示无返回值</li><li>示例：<code>void function();</code></li></ul></li></ul><p>======================================================</p><h2 id="_2-多数据存储类型" tabindex="-1">2. 多数据存储类型 <a class="header-anchor" href="#_2-多数据存储类型" aria-label="Permalink to &quot;2. 多数据存储类型&quot;">​</a></h2><ul><li><p><strong>数组</strong>：相同类型元素的集合</p><ul><li>语法格式：<code>类型 数组名[元素个数];</code></li><li>示例：<code>int arr[5] = {1, 2, 3, 4, 5};</code></li></ul></li><li><p><strong>结构体</strong>：不同类型元素的集合</p><ul><li>语法格式：<code>struct 结构体名 { 成员列表 };</code></li><li>示例：<code>struct Student { char name[20]; int age; float score; };</code></li></ul></li><li><p><strong>联合体</strong>：共用同一块内存的不同类型</p><ul><li>语法格式：<code>union 联合体名 { 成员列表 };</code></li><li>示例：<code>union Data { int i; float f; char c; };</code></li></ul></li><li><p><strong>枚举</strong>：命名的整型常量集合</p><ul><li>语法格式：<code>enum 枚举名 { 常量列表 };</code></li><li>示例：<code>enum Weekday { MON, TUE, WED, THU, FRI, SAT, SUN };</code></li></ul></li><li><p><strong>字符串</strong>：字符数组</p><ul><li>语法格式：<code>char 字符串名[长度];</code></li><li>示例：<code>char str[] = &quot;Hello&quot;;</code></li></ul></li></ul><p>======================================================</p><h2 id="_3-关键字" tabindex="-1">3. 关键字 <a class="header-anchor" href="#_3-关键字" aria-label="Permalink to &quot;3. 关键字&quot;">​</a></h2><ul><li><p><strong>const</strong>：声明常量，值不可修改</p><ul><li>适用类型：所有类型</li><li>示例：<code>const int MAX = 100;</code></li></ul></li><li><p><strong>typedef</strong>：类型别名</p><ul><li>适用类型：所有类型</li><li>示例：<code>typedef int Integer;</code></li></ul></li></ul>',11)])])}const _=i(a,[["render",c]]);export{h as __pageData,_ as default};
